  if (needed.length > requests.length) return 0;
  const need = {};
  for (const c of needed) need[c] = (need[c] || 0) + 1;
  const required = Object.keys(need).length;
  const window = {};
  let have = 0, best = Infinity, l = 0;
  for (let r = 0; r < requests.length; r++) {
