    window[c] = (window[c] || 0) + 1;
    if (need[c] !== undefined && window[c] === need[c]) have++;
    while (have === required) {
      if (r - l + 1 < best) best = r - l + 1;
      const lc = requests[l];
      window[lc]--;
      if (need[lc] !== undefined && window[lc] < need[lc]) have--;
      l++;
    }
  }
  return best === Infinity ? 0 : best;
}
