```js
function distinctPerWindow(merchants, k) {
  const n = merchants.length;
  if (k > n) return [];
  const freq = new Map();
  for (let i = 0; i < k; i++) freq.set(merchants[i], (freq.get(merchants[i]) || 0) + 1);
  const out = [freq.size];
  for (let i = k; i < n; i++) {
    const add = merchants[i], rem = merchants[i - k];
    freq.set(add, (freq.get(add) || 0) + 1);
    freq.set(rem, freq.get(rem) - 1);
    if (freq.get(rem) === 0) freq.delete(rem);
    out.push(freq.size);
  }
  return out;
}
```

**Time:** O(n). **Space:** O(k).

