**atMost(K):** Window mein at most K distinct. Right expand, agar distinct > K to left contract. Har r pe valid subarrays ending at r = `r - l + 1`.

```js
function subarraysWithKDistinct(events, k) {
  const atMost = (kk) => {
    if (kk < 0) return 0;
    const freq = new Map();
    let l = 0, count = 0;
    for (let r = 0; r < events.length; r++) {
      freq.set(events[r], (freq.get(events[r]) || 0) + 1);
      while (freq.size > kk) {
        freq.set(events[l], freq.get(events[l]) - 1);
        if (freq.get(events[l]) === 0) freq.delete(events[l]);
        l++;
      }
      count += r - l + 1;
    }
    return count;
  };
  return atMost(k) - atMost(k - 1);
}
```

**Time:** O(n). **Space:** O(k). Yeh 'exactly k' pattern bahut common hai counting problems mein.

